import{_ as a,o as i,c as s,ae as t}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"gRPC","description":"","frontmatter":{},"headers":[],"relativePath":"framework/grpc.md","filePath":"framework/grpc.md","lastUpdated":1776638516000}'),r={name:"framework/grpc.md"};function o(l,e,n,p,c,d){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="grpc" tabindex="-1">gRPC <a class="header-anchor" href="#grpc" aria-label="Permalink to &quot;gRPC&quot;">​</a></h1><p>EasyYapi supports exporting API documentation from gRPC service implementations.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>gRPC support can automatically recognize gRPC service classes and extract:</p><ul><li>gRPC service path (<code>/&lt;package&gt;.&lt;ServiceName&gt;/&lt;MethodName&gt;</code>)</li><li>Streaming type (unary, server-streaming, client-streaming, bidirectional)</li><li>Request/response protobuf message types</li></ul><h2 id="enable-grpc-support" tabindex="-1">Enable gRPC Support <a class="header-anchor" href="#enable-grpc-support" aria-label="Permalink to &quot;Enable gRPC Support&quot;">​</a></h2><p>gRPC support is enabled by default. You can toggle it in IDE settings:</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd></p><h2 id="class-recognition" tabindex="-1">Class Recognition <a class="header-anchor" href="#class-recognition" aria-label="Permalink to &quot;Class Recognition&quot;">​</a></h2><p>A class is recognized as a gRPC service if it meets any of the following conditions:</p><ol><li>Extends <code>io.grpc.BindableService</code> (or a generated <code>ImplBase</code> superclass)</li><li>Is annotated with <code>@GrpcService</code> (from <a href="https://yidongnan.github.io/grpc-spring-boot-starter/" target="_blank" rel="noreferrer">grpc-spring-boot-starter</a>)</li><li>Matches the <code>class.is.grpc</code> rule override</li></ol><h3 id="class-is-grpc-rule" tabindex="-1">class.is.grpc Rule <a class="header-anchor" href="#class-is-grpc-rule" aria-label="Permalink to &quot;class.is.grpc Rule&quot;">​</a></h3><p>The <code>class.is.grpc</code> rule can be used to customize gRPC service recognition. When this rule evaluates to <code>true</code> for a class, it is treated as a gRPC service regardless of the default detection logic.</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class.is.grpc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.isExtend(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.grpc.BindableService&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>See <a href="/settings/rules/class_is_grpc">class.is.grpc</a> for more details.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="grpc-call" tabindex="-1">gRPC Call <a class="header-anchor" href="#grpc-call" aria-label="Permalink to &quot;gRPC Call&quot;">​</a></h3><p>Enable gRPC call functionality to invoke gRPC methods directly from the IDE:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.call.enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><p>When gRPC call is enabled, you also need to configure the gRPC runtime dependencies. The plugin needs gRPC runtime JARs to invoke methods. You can use the <strong>Auto Detect</strong> button in the IDE settings panel to automatically detect and resolve the required dependencies.</p><h3 id="grpc-artifact-configs" tabindex="-1">gRPC Artifact Configs <a class="header-anchor" href="#grpc-artifact-configs" aria-label="Permalink to &quot;gRPC Artifact Configs&quot;">​</a></h3><p>Configure gRPC artifact coordinates for runtime dependency resolution. The format is <code>groupId:artifactId:version:enabled</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.artifact.configs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=io.grpc:grpc-netty-shaded:latest:true</span></span></code></pre></div><h3 id="grpc-additional-jars" tabindex="-1">gRPC Additional Jars <a class="header-anchor" href="#grpc-additional-jars" aria-label="Permalink to &quot;gRPC Additional Jars&quot;">​</a></h3><p>Add additional JAR files for runtime resolution:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.additional.jars</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/path/to/proto.jar</span></span></code></pre></div><h3 id="grpc-repositories" tabindex="-1">gRPC Repositories <a class="header-anchor" href="#grpc-repositories" aria-label="Permalink to &quot;gRPC Repositories&quot;">​</a></h3><p>Configure artifact repositories for dependency resolution. Supported types are <code>maven</code>, <code>gradle</code>, and <code>custom</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.repositories</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=maven:true:/Users/user/.m2/repository</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.repositories</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=gradle:true:/Users/user/.gradle/caches/modules-2/files-2.1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">grpc.repositories</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=custom:true:/path/to/custom/repo</span></span></code></pre></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guide/export-rpc">Export RPC Doc</a> — Exporting RPC documentation</li><li><a href="/guide/call#grpc-call">Call API</a> — Calling gRPC methods from the IDE</li><li><a href="/settings/ide-setting">IDE Settings</a> — Framework toggle settings</li></ul>`,31)])])}const u=a(r,[["render",o]]);export{h as __pageData,u as default};
